mapper.select:
SELECT COUNT(1)
FROM tb_policy
WHERE INSURED_IDENTITY_CARD = #{insuredIdNo}
  AND PRODUCT_CODE = #{productCode}
  AND POLICY_STATUS = 'PENDING'

      AND POLICY_NO != #{applicationId}

mapper.update:
UPDATE tb_policy
SET POLICY_STATUS = #{policyStatus},
    UPDATE_TIME   = CURRENT_TIMESTAMP,
    UPDATE_USER   = #{updateUser}
WHERE POLICY_NO = #{policyNo}
  AND POLICY_STATUS = 'PENDING'

mapper.select:
SELECT COUNT(1)
FROM tb_policy pa
         LEFT JOIN tb_cust_user cu ON pa.MEMBER_ID = cu.MEMBER_ID


        AND pa.POLICY_NO = #{applicationId}


        AND cu.IDENTITY_CARD = #{applicantIdNo}


        AND pa.INSURED_IDENTITY_CARD = #{insuredIdNo}


        AND pa.POLICY_STATUS = #{applicationStatus}


        AND pa.PRODUCT_CODE = #{productCode}


        AND pa.APPLY_TIME  >=  #{submissionStartTime}


        AND pa.APPLY_TIME  <=  #{submissionEndTime}

SELECT pa.application_id AS applicationId, pa.applicant_id_no AS applicantIdNo, pa.applicant_name AS applicantName, pa.applicant_gender AS applicantGender, pa.applicant_birthdate AS applicantBirthdate, pa.insured_id_no AS insuredIdNo, ip.insured_name AS insuredName, ip.insured_gender AS insuredGender, ip.insured_birthdate AS insuredBirthdate, ip.contact_phone AS contactPhone, pa.product_code AS productCode, p.PRODUCT_NAME AS productName, pa.application_status AS applicationStatus, pa.relationship_to_insured AS relationshipToInsured, pa.sum_insured AS sumInsured, pa.annual_premium AS annualPremium, pa.submission_time AS submissionTime, pa.review_time AS reviewTime, pa.reviewed_by AS reviewedBy, pa.rejection_reason AS rejectionReason, pa.created_by AS createdBy FROM policy_application pa INNER JOIN insured_person ip ON pa.application_id = ip.application_id INNER JOIN tb_product p ON pa.product_code = p.PRODUCT_CODE
AND pa.POLICY_NO = #{applicationId}
AND cu.IDENTITY_CARD = #{applicantIdNo}
AND pa.INSURED_IDENTITY_CARD = #{insuredIdNo}
AND pa.POLICY_STATUS = #{applicationStatus}
AND pa.PRODUCT_CODE = #{productCode}
AND pa.APPLY_TIME >= #{submissionStartTime}
AND pa.APPLY_TIME <= #{submissionEndTime}
ORDER BY pa.APPLY_TIME
ASC DESC
LIMIT #{offset}, #{pageSize}

SELECT pa.application_id AS applicationId, pa.applicant_id_no AS applicantIdNo, pa.applicant_name AS applicantName, pa.applicant_gender AS applicantGender, pa.applicant_birthdate AS applicantBirthdate, pa.insured_id_no AS insuredIdNo, ip.insured_name AS insuredName, ip.insured_gender AS insuredGender, ip.insured_birthdate AS insuredBirthdate, ip.contact_phone AS contactPhone, pa.product_code AS productCode, p.PRODUCT_NAME AS productName, pa.application_status AS applicationStatus, pa.relationship_to_insured AS relationshipToInsured, pa.sum_insured AS sumInsured, pa.annual_premium AS annualPremium, pa.submission_time AS submissionTime, pa.review_time AS reviewTime, pa.reviewed_by AS reviewedBy, pa.rejection_reason AS rejectionReason, pa.created_by AS createdBy FROM policy_application pa INNER JOIN insured_person ip ON pa.application_id = ip.application_id INNER JOIN tb_product p ON pa.product_code = p.PRODUCT_CODE WHERE pa.application_status IN
#{status}
ORDER BY pa.submission_time DESC
